const b = $input.first().json.body || $input.first().json;
const q = $input.first().json.query || {};

// Realtor.com field names differ slightly from Zillow
const firstName = b.buyer_first_name || b.firstName || b.first_name || '';
const lastName = b.buyer_last_name || b.lastName || b.last_name || '';

return [{
  json: {
    client_token: q.token || '',
    lead_name: `${firstName} ${lastName}`.trim() || b.name || b.contact_name || '',
    email: b.buyer_email || b.email || '',
    phone: b.buyer_phone || b.phone || '',
    source: 'realtor_com',
    property_address: b.listing_address || b.propertyAddress || b.property_address || '',
    price_range: b.listing_price ? `$${b.listing_price}` : b.price_range || '',
    beds: b.listing_beds || b.beds || null,
    lead_message: b.buyer_message || b.message || b.lead_message || ''
  }
}];
